/// Wrapper that includes version and checksum for integrity verification
#[derive(Debug, Serialize, Deserialize)]
struct CacheEnvelope {
    version: u32,
    checksum: u32,
    data: Vec<u8>,
}

/// Compute a CRC32 checksum of the data for integrity verification
fn compute_checksum(data: &[u8]) -> u32 {
    // Simple CRC32-like checksum (using a basic polynomial approach)
    let mut crc: u32 = 0xFFFFFFFF;
    for &byte in data {
        crc ^= byte as u32;
        for _ in 0..8 {
            if crc & 1 != 0 {
                crc = (crc >> 1) ^ 0xEDB88320;
            } else {
                crc >>= 1;
            }
        }
    }
    crc ^ 0xFFFFFFFF
}

